#include <iostream>
#include <thread>
#include <string>

void printMessage(const std::string& message) {
  std::cout << "Thread message: " << message << "\n";
}

int main() {
  std::thread t1(printMessage, "Hello from thread 1");
  std::thread t2(printMessage, "Hello from thread 2");
  t1.join();
  t2.join();
  std::cout << "Main thread done\n";
  return 0;
}
// Output (sıra dəyişə bilər):
// Thread message: Hello from thread 1
// Thread message: Hello from thread 2
// Main thread done

#include <iostream>
#include <thread>
#include <mutex>

std::mutex mtx;
int counter = 0;

void incrementCounter() {
  for (int i = 0; i < 1000; ++i) {
    mtx.lock();
    ++counter;
    mtx.unlock();
  }
}

int main() {
  std::thread t1(incrementCounter);
  std::thread t2(incrementCounter);
  t1.join();
  t2.join();
  std::cout << "Counter: " << counter << "\n";
  return 0;
}
// Output:
// Counter: 2000

#include <iostream>
#include <thread>
#include <mutex>

std::mutex mtx;
int counter = 0;

void incrementCounter() {
  for (int i = 0; i < 1000; ++i) {
    std::lock_guard<std::mutex> guard(mtx);
    ++counter;
  }
}

int main() {
  std::thread t1(incrementCounter);
  std::thread t2(incrementCounter);
  t1.join();
  t2.join();
  std::cout << "Counter: " << counter << "\n";
  return 0;
}
// Output:
// Counter: 2000

